using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class ModelTrainingService(ILogger<ModelTrainingService> logger, IWebHostEnvironment env)
{
    private readonly string _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
    private readonly string _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");

    /// <summary>Static helper used at startup before DI is available.</summary>
    public static TrainingMetrics TrainAndSave(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = BuildPipeline(mlContext);

        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        var result = new TrainingMetrics
        {
            MicroAccuracy = metrics.MicroAccuracy,
            MacroAccuracy = metrics.MacroAccuracy,
            LogLoss = metrics.LogLoss,
            ConfusionMatrix = metrics.ConfusionMatrix.GetFormattedConfusionTable()
        };

        Console.WriteLine(
            $"Model metrics — MicroAccuracy: {result.MicroAccuracy:F4}, " +
            $"MacroAccuracy: {result.MacroAccuracy:F4}, LogLoss: {result.LogLoss:F4}");

        mlContext.Model.Save(model, data.Schema, modelPath);
        Console.WriteLine($"Model saved to {modelPath}");

        return result;
    }

    /// <summary>Re-trains via the /retrain endpoint (has DI-injected logger).</summary>
    public TrainingMetrics Train()
    {
        logger.LogInformation("Retraining model from {Path}", _dataPath);
        var result = TrainAndSave(_dataPath, _modelPath);
        logger.LogInformation(
            "Retrained — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}",
            result.MicroAccuracy, result.MacroAccuracy, result.LogLoss);
        return result;
    }

    private static IEstimator<ITransformer> BuildPipeline(MLContext mlContext)
    {
        return mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
    }
}

